import sys
import inspect

sys.path.insert(0, '/opt/triposr')
import tsr.utils

for name, obj in inspect.getmembers(tsr.utils):
    if inspect.isfunction(obj):
        print(f'=== {name} ===')
        try:
            print(inspect.getsource(obj))
        except Exception as e:
            print(e)
